export type LogLevel = 'info' | 'warn' | 'error';

export class AppLogger {
    public static log(message: string, level: LogLevel = 'info'): void {
        const timestamp = new Date().toISOString();
        console.log(`[${timestamp}] [${level.toUpperCase()}] ${message}`);
    }
}

